1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: string; items: Item[] };
14	type Scenario = { steps: Step[] };
15	
16	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
17	
18	const sumItemBasePremiums = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
20	
21	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
22	  const step = (scenario as Scenario).steps[0];
23	  const itemsBase = sumItemBasePremiums(step.items);
24	  const policyBase = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE;
25	  const premium = policyBase + PROCESSING_FEE;
26	  return { results: [{ premium }] };
27	}
